var e=[{id:`L2_1`,type:`dialog`,speaker:`RIFLE_FOX_ENEMY_NULL`,text:{KOREA:`어엇? 대장님! 고도를 높일 수가 없습니다! 점점 내려가고 있어요!`,JPN:`うん？　隊長！　高度が上がりません！　むしろ下がってます！`,ENG:`Err? Captain! We're not gaining height! We're losing it!`,TWN:`呃？隊長！無法增加飛行高度！直升機正在下降！`},stage:{bg:`HELI_NIGHT_3`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}},sfx:`FX_COMBAT_ALL_HIT_METAL`},{id:`L3_1`,type:`dialog`,speaker:`RIFLE_FOX_ENEMY_BOSS`,text:{KOREA:`뭣? 그게 대체 무슨 소리야?`,JPN:`何だと？　それはどういうことだ？`,ENG:`What? What are you talking about?`,TWN:`什麼？到底是怎麼回事？`},stage:{bg:`HELI_NIGHT_3`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`RIFLE_FOX_ENEMY_BOSS`,face:`UNIT_IDLE`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`RIFLE_FOX_ENEMY_NULL`,text:{KOREA:`모르겠습니다! 갑자기 하중을 초과하는 엄청난 무게가......!`,JPN:`わかりません！　急に積載限度を超えるほどの重さが……！`,ENG:`I don't know! The load on the chopper suddenly has increased by the ton!`,TWN:`我不知道！直升機突然有超過負荷的重量……！`},stage:{bg:`HELI_NIGHT_3`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`RIFLE_FOX_ENEMY_BOSS`,face:`UNIT_IDLE`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`OGRE2_NPC_NULL_NULL`,text:{KOREA:`(검은 머리 여자! 못 데려간다!)`,JPN:`(黒髪の女！　連れて行かせない！)`,ENG:`(Black-haired female! You can't takes her!)`,TWN:`（黑髮女！不能帶走！）`},stage:{bg:`SKY_NIGHT`,bgm:`THEMA_HERO`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`HELI_STATE_NULL_NULL`,face:`UNIT_IDLE`},R:null}},sfx:`FX_COMBAT_MONSTER_BEAST_VOICE_36`},{id:`L10_1`,type:`dialog`,speaker:`OGRE1_NPC_NULL_NULL`,text:{KOREA:`(검은 머리 여자! 우리가 지킨다!)`,JPN:`(黒髪の女！　俺たちが守る！)`,ENG:`(Black-haired female! We protects her!)`,TWN:`（黑髮女！我們來保護！）`},stage:{bg:`SKY_NIGHT`,bgm:`THEMA_HERO`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`HELI_STATE_NULL_NULL`,face:`UNIT_IDLE`},R:null}},sfx:`FX_COMBAT_MONSTER_BEAST_VOICE_35`},{id:`L13_1`,type:`dialog`,speaker:`LONELY_NPC_SUMMER_NULL`,text:{KOREA:`서, 설마 너희들 날 구하러 온 거야?`,JPN:`ま、まさかあなたたち……私を助けに？`,ENG:`W-wait, did you come to save me?`,TWN:`難、難道你們是來救我的？`},stage:{bg:`HELI_NIGHT_3`,bgm:`THEMA_HERO`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LONELY_NPC_SUMMER_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`LONELY_NPC_SUMMER_NULL`,text:{KOREA:`난 너희들을 그렇게 이용만 했는데...... 어째서?`,JPN:`私はあなたたちを利用ばっかりしてたのに……どうして？`,ENG:`But... I only used you... Why?`,TWN:`我明明一直在利用你們……為什麼？`},stage:{bg:`HELI_NIGHT_3`,bgm:`THEMA_HERO`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LONELY_NPC_SUMMER_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`OGRE2_NPC_NULL_NULL`,text:{KOREA:`(좋아하니까! 구할 뿐이다!)`,JPN:`(好きだから！　助けるだけだ！)`,ENG:`(Likes you! Saves you!)`,TWN:`（因為喜歡！所以救！）`},stage:{bg:`HELI_NIGHT_3`,bgm:`THEMA_HERO`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LONELY_NPC_SUMMER_NULL`,face:`UNIT_IDLE`},R:null}},sfx:`FX_COMBAT_MONSTER_BEAST_VOICE_36`},{id:`L17_1`,type:`dialog`,speaker:`OGRE1_NPC_NULL_NULL`,text:{KOREA:`(구한다! 구한다!)`,JPN:`(助ける！　助ける！)`,ENG:`(Saves you! Saves you!)`,TWN:`（救妳！救妳！）`},stage:{bg:`HELI_NIGHT_3`,bgm:`THEMA_HERO`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LONELY_NPC_SUMMER_NULL`,face:`UNIT_IDLE`},R:null}},sfx:`FX_COMBAT_MONSTER_BEAST_VOICE_35`},{id:`L18_1`,type:`dialog`,speaker:`RIFLE_FOX_ENEMY_BOSS`,text:{KOREA:`이, 이 자식들! 어느새 여기까지 와서 헬기에 매달린 거지?`,JPN:`こ、こいつら！　いつの間にヘリにぶら下がったんだ？`,ENG:`Th-these monsters! When did they come this far? And why are they hanging onto our chopper?`,TWN:`這、這些東西！到底是什麼時候爬上直升機的？`},stage:{bg:`HELI_NIGHT_3`,bgm:`THEMA_HERO`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`RIFLE_FOX_ENEMY_BOSS`,face:`UNIT_IDLE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`RIFLE_FOX_ENEMY_BOSS`,text:{KOREA:`떨어져! 얼른 떨어지지 못해!`,JPN:`離れろ！　さっさと振り落とすんだ！`,ENG:`Get off! Get the hell off!`,TWN:`快滾開！離開這裡！`},stage:{bg:`HELI_NIGHT_3`,bgm:`THEMA_HERO`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`RIFLE_FOX_ENEMY_BOSS`,face:`UNIT_IDLE`},R:null}}},{id:`L21_1`,type:`dialog`,speaker:`RIFLE_FOX_ENEMY_NULL`,text:{KOREA:`대, 대장님! 이대로라면 카운터들에게 곧 따라 잡힐 겁니다!`,JPN:`た、隊長！　このままではカウンターたちに追いつかれます！`,ENG:`C-Captain! At this rate, the Counters will catch up with us!`,TWN:`隊、隊長！這樣下去，制裁者很快就會追上來的！`},stage:{bg:`HELI_NIGHT_3`,bgm:`THEMA_HERO`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`RIFLE_FOX_ENEMY_BOSS`,face:`UNIT_IDLE`},R:null}}},{id:`L22_1`,type:`dialog`,speaker:`RIFLE_FOX_ENEMY_NULL`,text:{KOREA:`어, 어쩌면 좋죠?`,JPN:`ど、どうすれば……？`,ENG:`W-what do we do?`,TWN:`怎、怎麼辦？`},stage:{bg:`HELI_NIGHT_3`,bgm:`THEMA_HERO`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`RIFLE_FOX_ENEMY_BOSS`,face:`UNIT_IDLE`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:`RIFLE_FOX_ENEMY_BOSS`,text:{KOREA:`어쩌긴! 어떻게든 떨어트려! 떨어트리라고!`,JPN:`どうにかして振り落とせ！　今すぐ！`,ENG:`Isn't it obvious? Do everything you can to lose them! Come on!`,TWN:`什麼怎麼辦！把它們打下去啊！打下去啊！`},stage:{bg:`HELI_NIGHT_3`,bgm:`THEMA_HERO`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`RIFLE_FOX_ENEMY_BOSS`,face:`UNIT_IDLE`},R:null}}}];export{e as default};